  1→import { useRef, useCallback } from 'react';
  2→import { getStarColor, getStarRadius, simpleHash } from '../utils/starUtils';
  3→
  4→// ── Constants ──────────────────────────────────────────────────────────
  5→const MAX_SPEED = 12;
  6→const ACCEL = 0.25;
  7→const BRAKE = 0.15;
  8→const FRICTION = 0.985;
  9→const YAW_RATE = 0.035;
 10→const PITCH_RATE = 0.025;
 11→const PITCH_MAX = (89 * Math.PI) / 180; // 89° in radians
 12→const MIN_VIEW_Z = 0.5;
 13→const SPAWN_DIST = 800;
 14→const RECYCLE_Z = 1200;
 15→const SORT_INTERVAL = 5;
 16→const TARGET_DIST_MAX = 150;
 17→const TARGET_Z_MIN = 2;
 18→const TWO_PI = Math.PI * 2;
 19→
 20→/** Max viewZ at which labels start fading in */
 21→export const LABEL_Z_MAX = 800;
 22→
 23→/** Parse "#5f92ff" → { r, g, b } */
 24→const parseHex = (hex) => ({
 25→    r: parseInt(hex.slice(1, 3), 16),
 26→    g: parseInt(hex.slice(3, 5), 16),
 27→    b: parseInt(hex.slice(5, 7), 16),
 28→});
 29→
 30→/** Seeded pseudo-random from integer seed */
 31→const seededRandom = (seed) => {
 32→    let s = seed | 0;
 33→    return () => {
 34→        s = (s * 1664525 + 1013904223) | 0;
 35→        return ((s >>> 0) / 4294967296);
 36→    };
 37→};
 38→
 39→/** Get forward direction vector from yaw + pitch */
 40→const getForwardVector = (yaw, pitch) => ({
 41→    x: Math.sin(yaw) * Math.cos(pitch),
 42→    y: Math.sin(pitch),
 43→    z: Math.cos(yaw) * Math.cos(pitch),
 44→});
 45→
 46→const useRocketMode = () => {
 47→    const isActiveRef = useRef(false);
 48→    const camPosRef = useRef({ x: 0, y: 0, z: 0 });
 49→    const yawRef = useRef(0);
 50→    const pitchRef = useRef(0);
 51→    const velocityRef = useRef(0);
 52→    const starsRef = useRef([]);
 53→    const sortedIndicesRef = useRef([]);
 54→    const keysRef = useRef({ w: false, s: false, a: false, d: false, q: false, e: false });
 55→    const targetIndexRef = useRef(-1);
 56→    const frameRef = useRef(0);
 57→    const layerRef = useRef(null);
 58→    const rafRef = useRef(null);
 59→    const stageSizeRef = useRef({ width: 0, height: 0 });
 60→
 61→    const sortStars = useCallback(() => {
 62→        const stars = starsRef.current;
 63→        const indices = sortedIndicesRef.current;
 64→        // Insertion sort — fast for nearly-sorted arrays, sort by viewZ descending (far first)
 65→        for (let i = 1; i < indices.length; i++) {
 66→            const key = indices[i];
 67→            let j = i - 1;
 68→            while (j >= 0 && stars[indices[j]].viewZ < stars[key].viewZ) {
 69→                indices[j + 1] = indices[j];
 70→                j--;
 71→            }
 72→            indices[j + 1] = key;
 73→        }
 74→    }, []);
 75→
 76→    const tick = useCallback(() => {
 77→        if (!isActiveRef.current) return;
 78→
 79→        const keys = keysRef.current;
 80→        const cam = camPosRef.current;
 81→        const stars = starsRef.current;
 82→        const size = stageSizeRef.current;
 83→
 84→        // ── Yaw (A/D) ───────────────────────────────────────────────
 85→        if (keys.a) yawRef.current -= YAW_RATE;
 86→        if (keys.d) yawRef.current += YAW_RATE;
 87→
 88→        // ── Pitch (Q/E), clamped ─────────────────────────────────────
 89→        if (keys.q) pitchRef.current = Math.min(pitchRef.current + PITCH_RATE, PITCH_MAX);
 90→        if (keys.e) pitchRef.current = Math.max(pitchRef.current - PITCH_RATE, -PITCH_MAX);
 91→
 92→        // ── Velocity ─────────────────────────────────────────────────
 93→        if (keys.w) {
 94→            velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
 95→        } else if (keys.s) {
 96→            velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
 97→        } else {
 98→            velocityRef.current *= FRICTION;
 99→            if (velocityRef.current < 0.01) velocityRef.current = 0;
100→        }
101→
102→        const yaw = yawRef.current;
103→        const pitch = pitchRef.current;
104→        const velocity = velocityRef.current;
105→
106→        // ── Position (move along forward vector) ─────────────────────
107→        const fwd = getForwardVector(yaw, pitch);
108→        cam.x += fwd.x * velocity;
109→        cam.y += fwd.y * velocity;
110→        cam.z += fwd.z * velocity;
111→
112→        // ── Pre-compute trig for view transform ──────────────────────
113→        const cosYaw = Math.cos(-yaw);
114→        const sinYaw = Math.sin(-yaw);
115→        const cosPitch = Math.cos(pitch);
116→        const sinPitch = Math.sin(pitch);
117→
118→        // ── View transform + recycling ───────────────────────────────
119→        for (let i = 0; i < stars.length; i++) {
120→            const star = stars[i];
121→
122→            // Translate to camera-relative
123→            const relX = star.worldX - cam.x;
124→            const relY = star.worldY - cam.y;
125→            const relZ = star.worldZ - cam.z;
126→
127→            // Yaw rotation (around Y axis)
128→            const rotX1 = relX * cosYaw + relZ * sinYaw;
129→            const rotZ1 = -relX * sinYaw + relZ * cosYaw;
130→
131→            // Pitch rotation (around X axis)
132→            const rotY2 = relY * cosPitch - rotZ1 * sinPitch;
133→            const viewZ = relY * sinPitch + rotZ1 * cosPitch;
134→
135→            // Cache on star for renderer
136→            star._rotX1 = rotX1;
137→            star._rotY2 = rotY2;
138→            star.viewZ = viewZ;
139→
140→            // Recycle stars that are behind camera or too far
141→            if (viewZ < MIN_VIEW_Z || viewZ > RECYCLE_Z) {
142→                // Respawn ahead of camera using forward vector + random spread
143→                const dist = SPAWN_DIST * (0.5 + Math.random() * 0.5);
144→                const spreadX = (Math.random() - 0.5) * 2000;
145→                const spreadY = (Math.random() - 0.5) * 2000;
146→                star.worldX = cam.x + fwd.x * dist + spreadX;
147→                star.worldY = cam.y + fwd.y * dist + spreadY;
148→                star.worldZ = cam.z + fwd.z * dist + (Math.random() - 0.5) * 1000;
149→
150→                // Recompute view-space for the recycled position
151→                const rX = star.worldX - cam.x;
152→                const rY = star.worldY - cam.y;
153→                const rZ = star.worldZ - cam.z;
154→                const rX1 = rX * cosYaw + rZ * sinYaw;
155→                const rZ1 = -rX * sinYaw + rZ * cosYaw;
156→                star._rotX1 = rX1;
157→                star._rotY2 = rY * cosPitch - rZ1 * sinPitch;
158→                star.viewZ = rY * sinPitch + rZ1 * cosPitch;
159→            }
160→        }
161→
162→        // ── Sort (every N frames) ────────────────────────────────────
163→        frameRef.current++;
164→        if (frameRef.current % SORT_INTERVAL === 0) {
165→            sortStars();
166→        }
167→
168→        // ── Target detection ─────────────────────────────────────────
169→        const cx = size.width / 2;
170→        const cy = size.height / 2;
171→        const focalLength = size.width * 0.6;
172→        let bestIdx = -1;
173→        let bestDist = TARGET_DIST_MAX;
174→
175→        for (let i = 0; i < stars.length; i++) {
176→            const star = stars[i];
177→            if (star.viewZ < TARGET_Z_MIN) continue;
178→            const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
179→            const projY = cy - (star._rotY2 / star.viewZ) * focalLength;
180→            const dx = projX - cx;
181→            const dy = projY - cy;
182→            const dist = Math.sqrt(dx * dx + dy * dy);
183→            if (dist < bestDist) {
184→                bestDist = dist;
185→                bestIdx = i;
186→            }
187→        }
188→        targetIndexRef.current = bestIdx;
189→
190→        // ── Redraw ───────────────────────────────────────────────────
191→        if (layerRef.current) {
192→            layerRef.current.batchDraw();
193→        }
194→
195→        rafRef.current = requestAnimationFrame(tick);
196→    }, [sortStars]);
197→
198→    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
199→        stageSizeRef.current = stageSize;
200→        camPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y, z: 0 };
201→        yawRef.current = 0;
202→        pitchRef.current = 0;
203→        velocityRef.current = 0;
204→        frameRef.current = 0;
205→        targetIndexRef.current = -1;
206→
207→        // Build star array from posts — distributed in 3D volume
208→        const stars = [];
209→        for (let i = 0; i < galaxyPosts.length; i++) {
210→            const post = galaxyPosts[i];
211→            const uid = post.users?.id ?? post.user_id;
212→            const likeCount = post.like_count != null
213→                ? post.like_count
214→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
215→                    ? post.likes[0].count : 0);
216→            const color = getStarColor(uid);
217→            const rng = seededRandom(simpleHash(post.id || String(i)));
218→            stars.push({
219→                postId: post.id,
220→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
221→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
222→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2, // ±SPAWN_DIST from camera z=0
223→                viewZ: 0,
224→                _rotX1: 0,
225→                _rotY2: 0,
226→                color,
227→                colorRgb: parseHex(color),
228→                radius: getStarRadius(likeCount),
229→                title: post.title || 'Untitled',
230→                authorName: post.users?.name || post.user_name || 'Anonymous',
231→                post,
232→            });
233→        }
234→
235→        starsRef.current = stars;
236→
237→        // Build sorted indices (far → near by viewZ, will be sorted properly on first tick)
238→        const indices = new Array(stars.length);
239→        for (let i = 0; i < stars.length; i++) indices[i] = i;
240→        sortedIndicesRef.current = indices;
241→
242→        // Key listeners
243→        const onKeyDown = (e) => {
244→            const key = e.key.toLowerCase();
245→            if (key === 'w') keysRef.current.w = true;
246→            if (key === 's') keysRef.current.s = true;
247→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
248→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
249→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
250→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
251→        };
252→        const onKeyUp = (e) => {
253→            const key = e.key.toLowerCase();
254→            if (key === 'w') keysRef.current.w = false;
255→            if (key === 's') keysRef.current.s = false;
256→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
257→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
258→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
259→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
260→        };
261→
262→        window.addEventListener('keydown', onKeyDown);
263→        window.addEventListener('keyup', onKeyUp);
264→
265→        // Reset keys
266→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
267→        isActiveRef.current = true;
268→
269→        // Store listener refs for cleanup
270→        camPosRef.current._onKeyDown = onKeyDown;
271→        camPosRef.current._onKeyUp = onKeyUp;
272→
273→        // Start rAF
274→        rafRef.current = requestAnimationFrame(tick);
275→    }, [tick]);
276→
277→    const exit = useCallback(() => {
278→        isActiveRef.current = false;
279→        if (rafRef.current) {
280→            cancelAnimationFrame(rafRef.current);
281→            rafRef.current = null;
282→        }
283→        // Remove key listeners
284→        const cam = camPosRef.current;
285→        if (cam._onKeyDown) {
286→            window.removeEventListener('keydown', cam._onKeyDown);
287→            window.removeEventListener('keyup', cam._onKeyUp);
288→            delete cam._onKeyDown;
289→            delete cam._onKeyUp;
290→        }
291→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
292→    }, []);
293→
294→    const project = useCallback((star, cx, cy) => {
295→        if (star.viewZ <= MIN_VIEW_Z) return null; // behind camera
296→
297→        const stageWidth = stageSizeRef.current.width;
298→        const focalLength = stageWidth * 0.6; // ~80° FOV
299→        const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
300→        const projY = cy - (star._rotY2 / star.viewZ) * focalLength; // negate Y for screen coords
301→        const scale = focalLength / star.viewZ;
302→
303→        return { projX, projY, scale };
304→    }, []);
305→
306→    const getTargetedPost = useCallback(() => {
307→        const idx = targetIndexRef.current;
308→        if (idx < 0 || idx >= starsRef.current.length) return null;
309→        return starsRef.current[idx].post;
310→    }, []);
311→
312→    const getSpeedRatio = useCallback(() => {
313→        return velocityRef.current / MAX_SPEED;
314→    }, []);
315→
316→    return {
317→        enter,
318→        exit,
319→        layerRef,
320→        starsRef,
321→        sortedIndicesRef,
322→        rocketPos: camPosRef,
323→        heading: yawRef,
324→        pitch: pitchRef,
325→        velocity: velocityRef,
326→        targetIndexRef,
327→        stageSizeRef,
328→        project,
329→        isActive: isActiveRef,
330→        getTargetedPost,
331→        getSpeedRatio,
332→    };
333→};
334→
335→export default useRocketMode;
336→

  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→import { LABEL_Z_MAX } from '../hooks/useRocketMode';
  4→
  5→const TWO_PI = Math.PI * 2;
  6→const SPEED_LINE_COUNT = 30;
  7→
  8→const RocketLayer = React.memo(({ rocketMode }) => {
  9→    const {
 10→        layerRef, starsRef, sortedIndicesRef, velocity, targetIndexRef,
 11→        stageSizeRef, project, getSpeedRatio,
 12→    } = rocketMode;
 13→
 14→    const shapeRef = useRef(null);
 15→    const timeRef = useRef(0);
 16→
 17→    // Attach the Konva Layer ref so the hook can call batchDraw
 18→    const layerCallbackRef = useCallback((node) => {
 19→        layerRef.current = node;
 20→    }, [layerRef]);
 21→
 22→    // Keep time ticking for pulsing effects
 23→    useEffect(() => {
 24→        const update = () => {
 25→            timeRef.current = performance.now();
 26→        };
 27→        const id = setInterval(update, 16);
 28→        return () => clearInterval(id);
 29→    }, []);
 30→
 31→    return (
 32→        <Layer ref={layerCallbackRef} listening={false}>
 33→            <Shape
 34→                ref={shapeRef}
 35→                sceneFunc={(ctx) => {
 36→                    const size = stageSizeRef.current;
 37→                    const cx = size.width / 2;
 38→                    const cy = size.height / 2;
 39→                    const stars = starsRef.current;
 40→                    const sorted = sortedIndicesRef.current;
 41→                    const speedRatio = getSpeedRatio();
 42→                    const time = timeRef.current || performance.now();
 43→                    const targetIdx = targetIndexRef.current;
 44→                    const bufferX = size.width / 2 + 200;
 45→                    const bufferY = size.height / 2 + 200;
 46→                    const focalLength = size.width * 0.6;
 47→
 48→                    // ── 1. Speed lines — converging streaks toward center ─
 49→                    if (speedRatio > 0.4) {
 50→                        const lineAlpha = (speedRatio - 0.4) / 0.6;
 51→                        ctx.strokeStyle = `rgba(180,210,255,${lineAlpha * 0.3})`;
 52→                        ctx.lineWidth = 1;
 53→
 54→                        for (let i = 0; i < SPEED_LINE_COUNT; i++) {
 55→                            const angle = (i / SPEED_LINE_COUNT) * TWO_PI;
 56→                            const outerR = 200 + speedRatio * 300 + Math.sin(time * 0.002 + i) * 20;
 57→                            const innerR = 40 + speedRatio * 60;
 58→                            ctx.beginPath();
 59→                            ctx.moveTo(
 60→                                cx + Math.cos(angle) * outerR,
 61→                                cy + Math.sin(angle) * outerR
 62→                            );
 63→                            ctx.lineTo(
 64→                                cx + Math.cos(angle) * innerR,
 65→                                cy + Math.sin(angle) * innerR
 66→                            );
 67→                            ctx.stroke();
 68→                        }
 69→                    }
 70→
 71→                    // ── 2. Stars (painter's algorithm, far first) ────────
 72→                    for (let si = 0; si < sorted.length; si++) {
 73→                        const idx = sorted[si];
 74→                        const star = stars[idx];
 75→                        const projected = project(star, cx, cy);
 76→
 77→                        // Null guard — star is behind camera
 78→                        if (!projected) continue;
 79→
 80→                        const { projX, projY, scale } = projected;
 81→
 82→                        // Viewport cull
 83→                        if (projX < cx - bufferX || projX > cx + bufferX ||
 84→                            projY < cy - bufferY || projY > cy + bufferY) continue;
 85→
 86→                        const baseRadius = star.radius * scale * 0.08;
 87→                        if (baseRadius < 0.3) continue;
 88→
 89→                        const stretchX = 1 + speedRatio * 2.5;
 90→                        const opacity = Math.max(0.1, 1 - speedRatio * 0.6);
 91→                        const drawR = Math.min(baseRadius, 60);
 92→                        const { r, g, b } = star.colorRgb;
 93→
 94→                        ctx.save();
 95→                        ctx.translate(projX, projY);
 96→                        ctx.scale(stretchX, 1);
 97→
 98→                        // Outer glow
 99→                        const glowR = drawR * 2.5;
100→                        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, glowR);
101→                        grad.addColorStop(0, `rgba(${r},${g},${b},${opacity * 0.5})`);
102→                        grad.addColorStop(0.4, `rgba(${r},${g},${b},${opacity * 0.15})`);
103→                        grad.addColorStop(1, 'rgba(0,0,0,0)');
104→                        ctx.beginPath();
105→                        ctx.arc(0, 0, glowR, 0, TWO_PI);
106→                        ctx.fillStyle = grad;
107→                        ctx.fill();
108→
109→                        // Core (white-hot center)
110→                        const coreR = drawR * 0.4;
111→                        ctx.beginPath();
112→                        ctx.arc(0, 0, Math.max(coreR, 0.5), 0, TWO_PI);
113→                        ctx.fillStyle = `rgba(255,255,255,${opacity * 0.9})`;
114→                        ctx.fill();
115→
116→                        ctx.restore();
117→
118→                        // ── Dynamic label (when close) ───────────────────
119→                        const viewZ = star.viewZ;
120→                        if (viewZ > 0 && viewZ < LABEL_Z_MAX) {
121→                            const labelOpacity = (1 - viewZ / LABEL_Z_MAX) * (1 - speedRatio * 0.8);
122→                            if (labelOpacity > 0.05) {
123→                                const rawFontSize = focalLength * star.radius / viewZ * 0.015;
124→                                const fontSize = Math.max(10, Math.min(18, rawFontSize));
125→                                const labelY = projY + drawR * stretchX * 1.8 + fontSize;
126→
127→                                // Title
128→                                ctx.font = `bold ${fontSize}px sans-serif`;
129→                                ctx.fillStyle = `rgba(255,255,255,${labelOpacity * 0.9})`;
130→                                ctx.textAlign = 'center';
131→                                ctx.fillText(star.title, projX, labelY);
132→
133→                                // Author (smaller, blue-tinted)
134→                                const authorSize = Math.max(9, fontSize * 0.75);
135→                                ctx.font = `${authorSize}px sans-serif`;
136→                                ctx.fillStyle = `rgba(140,180,255,${labelOpacity * 0.7})`;
137→                                ctx.fillText(star.authorName, projX, labelY + authorSize + 2);
138→                            }
139→                        }
140→
141→                        // ── 3. Targeting bracket ─────────────────────────
142→                        if (idx === targetIdx) {
143→                            const pulse = 0.6 + 0.4 * Math.sin(time * 0.004);
144→                            const bracketSize = Math.max(drawR * stretchX * 4, 18);
145→                            const half = bracketSize / 2;
146→                            const arm = bracketSize * 0.35;
147→
148→                            ctx.strokeStyle = `rgba(0,255,255,${pulse})`;
149→                            ctx.lineWidth = 1.5;
150→                            ctx.setLineDash([3, 3]);
151→
152→                            // Top-left
153→                            ctx.beginPath();
154→                            ctx.moveTo(projX - half, projY - half + arm);
155→                            ctx.lineTo(projX - half, projY - half);
156→                            ctx.lineTo(projX - half + arm, projY - half);
157→                            ctx.stroke();
158→
159→                            // Top-right
160→                            ctx.beginPath();
161→                            ctx.moveTo(projX + half - arm, projY - half);
162→                            ctx.lineTo(projX + half, projY - half);
163→                            ctx.lineTo(projX + half, projY - half + arm);
164→                            ctx.stroke();
165→
166→                            // Bottom-right
167→                            ctx.beginPath();
168→                            ctx.moveTo(projX + half, projY + half - arm);
169→                            ctx.lineTo(projX + half, projY + half);
170→                            ctx.lineTo(projX + half - arm, projY + half);
171→                            ctx.stroke();
172→
173→                            // Bottom-left
174→                            ctx.beginPath();
175→                            ctx.moveTo(projX - half + arm, projY + half);
176→                            ctx.lineTo(projX - half, projY + half);
177→                            ctx.lineTo(projX - half, projY + half - arm);
178→                            ctx.stroke();
179→
180→                            ctx.setLineDash([]);
181→                        }
182→                    }
183→                }}
184→                perfectDrawEnabled={false}
185→                listening={false}
186→            />
187→        </Layer>
188→    );
189→});
190→
191→RocketLayer.displayName = 'RocketLayer';
192→
193→export default RocketLayer;
194→

  1→import { useState, useEffect, useRef, useCallback } from 'react';
  2→import styles from '../Universe.module.css';
  3→
  4→const RocketHUD = ({ rocketMode, onExit, onInteract }) => {
  5→    const [speed, setSpeed] = useState(0);
  6→    const [pitch, setPitch] = useState(0);
  7→    const [targetInfo, setTargetInfo] = useState(null);
  8→    const pollRef = useRef(null);
  9→
 10→    // Poll refs at 10 Hz for HUD display
 11→    useEffect(() => {
 12→        pollRef.current = setInterval(() => {
 13→            setSpeed(rocketMode.getSpeedRatio());
 14→
 15→            // Read pitch in degrees
 16→            if (rocketMode.pitch) {
 17→                setPitch(Math.round((rocketMode.pitch.current * 180) / Math.PI));
 18→            }
 19→
 20→            const idx = rocketMode.targetIndexRef.current;
 21→            const stars = rocketMode.starsRef.current;
 22→            if (idx >= 0 && idx < stars.length) {
 23→                const star = stars[idx];
 24→                setTargetInfo({ title: star.title, author: star.authorName });
 25→            } else {
 26→                setTargetInfo(null);
 27→            }
 28→        }, 100);
 29→
 30→        return () => {
 31→            if (pollRef.current) clearInterval(pollRef.current);
 32→        };
 33→    }, [rocketMode]);
 34→
 35→    // Key bindings for Enter/Space (interact) and Escape (exit)
 36→    const handleKey = useCallback((e) => {
 37→        if (e.key === 'Enter' || e.key === ' ') {
 38→            e.preventDefault();
 39→            onInteract();
 40→        } else if (e.key === 'Escape') {
 41→            e.preventDefault();
 42→            onExit();
 43→        }
 44→    }, [onInteract, onExit]);
 45→
 46→    useEffect(() => {
 47→        window.addEventListener('keydown', handleKey);
 48→        return () => window.removeEventListener('keydown', handleKey);
 49→    }, [handleKey]);
 50→
 51→    const absPitch = Math.abs(pitch);
 52→
 53→    return (
 54→        <div className={styles.rocketHud}>
 55→            {/* Exit button */}
 56→            <button className={styles.rocketExitBtn} onClick={onExit}>
 57→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
 58→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 59→                </svg>
 60→                Exit Rocket
 61→            </button>
 62→
 63→            {/* Pitch indicator (top-right, only when |pitch| > 5°) */}
 64→            {absPitch > 5 && (
 65→                <div className={styles.rocketPitch}>
 66→                    {pitch > 0 ? '\u2191' : '\u2193'} {absPitch}\u00B0
 67→                </div>
 68→            )}
 69→
 70→            {/* Target info (below center) */}
 71→            {targetInfo && (
 72→                <div className={styles.rocketTarget}>
 73→                    <div className={styles.rocketTargetTitle}>{targetInfo.title}</div>
 74→                    <div className={styles.rocketTargetAuthor}>by {targetInfo.author}</div>
 75→                    <div className={styles.rocketTargetPrompt}>Press ENTER to read</div>
 76→                </div>
 77→            )}
 78→
 79→            {/* Speed bar */}
 80→            <div className={styles.rocketSpeedBar}>
 81→                <span className={styles.rocketSpeedLabel}>SPD</span>
 82→                <div className={styles.rocketSpeedTrack}>
 83→                    <div
 84→                        className={styles.rocketSpeedFill}
 85→                        style={{ width: `${Math.round(speed * 100)}%` }}
 86→                    />
 87→                </div>
 88→                <span className={styles.rocketSpeedValue}>{Math.round(speed * 100)}%</span>
 89→            </div>
 90→
 91→            {/* Controls hint */}
 92→            <div className={styles.rocketControls}>
 93→                <span>W/S Throttle</span>
 94→                <span>A/D Yaw</span>
 95→                <span>Q/E Pitch</span>
 96→                <span>ENTER Read</span>
 97→                <span>ESC Exit</span>
 98→            </div>
 99→        </div>
100→    );
101→};
102→
103→export default RocketHUD;
