  94→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
  95→    const showTitles = zoom > 0.5;
  96→
  97→    // Sector partitioning for scalable local gravity math.
  98→    const postSectorIndex = useMemo(() => (
  99→        buildSectorIndex(
 100→            postArray,
 101→            (post) => ({
 102→                x: post?.display_x ?? post?.universe_x,
 103→                y: post?.display_y ?? post?.universe_y,
 104→            }),
 105→            SECTOR_SIZE
 106→        )
 107→    ), [postArray]);
