 109→    const centerSectorKey = useMemo(
 110→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 111→        [centerWorld.x, centerWorld.y]
 112→    );
 113→
 114→    const activeSectorKeys = useMemo(
 115→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
 116→        [centerSectorKey]
 117→    );
 118→
 119→    const activePosts = useMemo(() => {
 120→        if (activeSectorKeys.size === 0) return postArray;
 121→
 122→        const next = [];
 123→        for (const key of activeSectorKeys) {
 124→            const bucket = postSectorIndex.get(key);
 125→            if (bucket?.length) next.push(...bucket);
 126→        }
 127→        return next;
 128→    }, [postArray, postSectorIndex, activeSectorKeys]);
 129→
 130→    const activePostIds = useMemo(() => {
 131→        const ids = new Set();
 132→        for (const post of activePosts) {
 133→            if (post?.id) ids.add(post.id);
 134→        }
 135→        return ids;
 136→    }, [activePosts]);
