 138→    const { centroidByUser } = useMemo(
 139→        () => computeGalaxyCentroids(postArray),
 140→        [postArray]
 141→    );
 142→
 143→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
 144→    const hashGalaxies = useMemo(() => {
 145→        const seen = new Map();
 146→        for (const post of postArray) {
 147→            const uid = post.users?.id ?? post.user_id;
 148→            if (!uid || seen.has(uid)) continue;
 149→            const hash = userHomeCoords(uid);
 150→            seen.set(uid, {
 151→                userId: uid,
 152→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
 153→                x: hash.x,
 154→                y: hash.y,
 155→            });
 156→        }
 157→        return Array.from(seen.values());
 158→    }, [postArray]);
 159→
 160→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
 161→    const centroidTargets = useMemo(() => {
 162→        const map = new Map();
 163→        for (const c of centroids) {
 164→            if (c.galaxy_x != null && c.galaxy_y != null) {
 165→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
 166→            }
 167→        }
 168→        return map;
 169→    }, [centroids]);
 170→
 171→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
 172→    const {
 173→        galaxyPositions,
 174→        starPullOffsets,
 175→        isSettled,
 176→        galaxyEdges: effectiveGalaxyEdges,
 177→        hasEmbeddingGravity,
 178→    } = useCosmicGravity({
 179→        galaxies: hashGalaxies,
 180→        centroidTargets,
 181→        edges: galaxyEdges,
 182→        posts: postArray,
 183→        starPulls,
 184→        centroidByUser,
 185→        activeSectorKeys,
 186→        activePostIds,
 187→        sectorSize: SECTOR_SIZE,
 188→    });
 189→
 190→    // ── Render galaxies = hash galaxies with animated positions ──────
 191→    const galaxies = useMemo(() => {
 192→        return hashGalaxies.map(g => {
 193→            const animated = galaxyPositions.get(g.userId);
 194→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
 195→        });
 196→    }, [hashGalaxies, galaxyPositions]);
 197→
 198→    // Home position for distance tracker — same resolution as auto-focus.
 199→    const homePosition = useMemo(() => {
 200→        if (!userId) return { x: 0, y: 0 };
 201→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
 202→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
 203→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
 204→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
 205→
 206→    const getComputedStarPosition = useCallback((post) => {
 207→        if (!post) return null;
 208→
 209→        const uid = post.users?.id ?? post.user_id;
 210→        const hashGal = userHomeCoords(uid);
 211→        const animGal = galaxyPositions.get(uid);
 212→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 213→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 214→        const pull = starPullOffsets.get(post.id);
 215→
 216→        const baseX = post.universe_x ?? post.display_x;
 217→        const baseY = post.universe_y ?? post.display_y;
 218→        if (baseX == null || baseY == null) return null;
 219→
 220→        return {
 221→            x: baseX + galDx + (pull?.dx ?? 0),
 222→            y: baseY + galDy + (pull?.dy ?? 0),
 223→        };
 224→    }, [galaxyPositions, starPullOffsets]);
 225→
 226→    // ── Hoisted computedStarPositions for sharing across layers ──────
 227→    const computedStarPositions = useMemo(() => {
 228→        const map = new Map();
 229→        for (const post of postArray) {
 230→            const uid = post.users?.id ?? post.user_id;
 231→            const hashGal = userHomeCoords(uid);
 232→            const animGal = galaxyPositions.get(uid);
 233→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 234→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 235→            const pull = starPullOffsets.get(post.id);
 236→
 237→            const baseX = post.universe_x ?? post.display_x;
 238→            const baseY = post.universe_y ?? post.display_y;
 239→            if (baseX == null || baseY == null) continue;
 240→
 241→            let x = baseX + galDx + (pull?.dx ?? 0);
 242→            let y = baseY + galDy + (pull?.dy ?? 0);
 243→
 244→            map.set(post.id, { x, y });
 245→        }
 246→        return map;
 247→    }, [postArray, galaxyPositions, starPullOffsets]);
 248→
 249→    // ── Constellation pull offsets (spring constraint) ─────────────
 250→    const acceptedConstellations = useMemo(
 251→        () => constellations.filter(c => c.status === 'accepted'),
 252→        [constellations]
 253→    );
 254→
 255→    const constellationPullOffsets = useMemo(
 256→        () => computeConstellationPullOffsets(acceptedConstellations, computedStarPositions),
 257→        [acceptedConstellations, computedStarPositions]
 258→    );
 259→
 260→    // ── Final star positions with constellation pull applied ───────
 261→    const finalStarPositions = useMemo(() => {
 262→        if (constellationPullOffsets.size === 0) return computedStarPositions;
 263→
 264→        const map = new Map(computedStarPositions);
 265→        for (const [postId, offset] of constellationPullOffsets) {
 266→            const pos = map.get(postId);
 267→            if (pos) {
 268→                map.set(postId, {
 269→                    x: pos.x + offset.dx,
 270→                    y: pos.y + offset.dy,
