63→export const hexToRgba = (hex, alpha) => {
64→    const r = parseInt(hex.slice(1, 3), 16);
65→    const g = parseInt(hex.slice(3, 5), 16);
66→    const b = parseInt(hex.slice(5, 7), 16);
67→    return `rgba(${r},${g},${b},${alpha})`;
68→};
