 601→        if (constellationFlyToRef.current) return;
 602→
 603→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
 604→        const target = ownGalaxy
 605→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
 606→            : (centroidTargets.get(userId) || ownGalaxyTarget);
 607→
 608→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
 609→        if (!target) return;
 610→
 611→        hasAutoFocusedOwnGalaxyRef.current = true;
 612→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
 613→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
 614→
 615→    // Fly to constellation midpoint when arriving from a notification link.
 616→    useEffect(() => {
 617→        const target = constellationFlyToRef.current;
 618→        if (!target) return;
 619→        if (isInitialLoading) return;
 620→
 621→        const posA = finalStarPositions.get(target.starIdA);
 622→        const posB = finalStarPositions.get(target.starIdB);
 623→        if (!posA || !posB) return;
 624→
 625→        constellationFlyToRef.current = null;
 626→        hasAutoFocusedOwnGalaxyRef.current = true;
 627→
 628→        const mx = (posA.x + posB.x) / 2;
 629→        const my = (posA.y + posB.y) / 2;
 630→        flyTo(mx, my, 1.0);
 631→
 632→        // Clear navigation state so refreshing doesn't re-trigger
 633→        navigate(location.pathname, { replace: true, state: {} });
 634→    }, [isInitialLoading, finalStarPositions, flyTo, navigate, location.pathname]);
 635→
 636→    const settledPayload = useMemo(() => {
 637→        if (!isSettled || activePosts.length === 0) return [];
 638→
 639→        const payload = [];
 640→        for (const post of activePosts) {
 641→            if (!post?.id) continue;
 642→            const pos = getComputedStarPosition(post);
 643→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
 644→
 645→            payload.push({
 646→                post_id: post.id,
 647→                settled_x: Math.round(pos.x * 100) / 100,
 648→                settled_y: Math.round(pos.y * 100) / 100,
 649→            });
 650→        }
 651→
 652→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
 653→        return payload;
 654→    }, [activePosts, getComputedStarPosition, isSettled]);
 655→
 656→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
 657→    useEffect(() => {
 658→        if (!ENABLE_SETTLED_RPC_SAVE) return;
 659→        if (!isSettled || settledPayload.length === 0) return;
 660→
 661→        const signature = JSON.stringify(settledPayload);
 662→        if (signature === lastSettledPayloadRef.current) return;
 663→
 664→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 665→        settleDebounceRef.current = setTimeout(async () => {
 666→            lastSettledPayloadRef.current = signature;
 667→            try {
 668→                const { error } = await supabase.rpc('save_universe_settled_positions', {
 669→                    positions_payload: settledPayload,
 670→                });
 671→                if (error) {
 672→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
 673→                }
 674→            } catch (err) {
 675→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
 676→            }
 677→        }, 1200);
 678→
 679→        return () => {
 680→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 681→        };
 682→    }, [isSettled, settledPayload]);
 683→
 684→    // ESC key to cancel link mode or dismiss constellation focus
 685→    useEffect(() => {
 686→        if (universeMode !== 'strategic') return;
 687→        if (!isLinkMode && !focusedConstellation) return;
 688→        const handleKeyDown = (e) => {
 689→            if (e.key === 'Escape') {
 690→                if (isLinkMode) cancelLinkMode();
 691→                if (focusedConstellation) setFocusedConstellation(null);
 692→            }
 693→        };
 694→        window.addEventListener('keydown', handleKeyDown);
 695→        return () => window.removeEventListener('keydown', handleKeyDown);
 696→    }, [isLinkMode, cancelLinkMode, focusedConstellation, universeMode]);
 697→
 698→    useEffect(() => {
 699→        return () => {
 700→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
 701→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 702→            rocketMode.exit();
 703→        };
 704→    }, []);
 705→
 706→    return (
