  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→import { LABEL_Z_MAX } from '../hooks/useRocketMode';
  4→
  5→const TWO_PI = Math.PI * 2;
  6→const SPEED_LINE_COUNT = 30;
  7→
  8→const RocketLayer = React.memo(({ rocketMode }) => {
  9→    const {
 10→        layerRef, starsRef, sortedIndicesRef, velocity, targetIndexRef,
 11→        stageSizeRef, project, getSpeedRatio,
 12→    } = rocketMode;
 13→
 14→    const shapeRef = useRef(null);
 15→    const timeRef = useRef(0);
 16→
 17→    // Attach the Konva Layer ref so the hook can call batchDraw
 18→    const layerCallbackRef = useCallback((node) => {
 19→        layerRef.current = node;
 20→    }, [layerRef]);
 21→
 22→    // Keep time ticking for pulsing effects
 23→    useEffect(() => {
 24→        const update = () => {
 25→            timeRef.current = performance.now();
 26→        };
 27→        const id = setInterval(update, 16);
 28→        return () => clearInterval(id);
 29→    }, []);
 30→
 31→    return (
 32→        <Layer ref={layerCallbackRef} listening={false}>
 33→            <Shape
 34→                ref={shapeRef}
 35→                sceneFunc={(ctx) => {
 36→                    const size = stageSizeRef.current;
 37→                    const cx = size.width / 2;
 38→                    const cy = size.height / 2;
 39→                    const stars = starsRef.current;
 40→                    const sorted = sortedIndicesRef.current;
 41→                    const speedRatio = getSpeedRatio();
 42→                    const time = timeRef.current || performance.now();
 43→                    const targetIdx = targetIndexRef.current;
 44→                    const bufferX = size.width / 2 + 200;
 45→                    const bufferY = size.height / 2 + 200;
 46→                    const focalLength = size.width * 0.6;
 47→
 48→                    // ── 1. Speed lines — converging streaks toward center ─
 49→                    if (speedRatio > 0.4) {
 50→                        const lineAlpha = (speedRatio - 0.4) / 0.6;
 51→                        ctx.strokeStyle = `rgba(180,210,255,${lineAlpha * 0.3})`;
 52→                        ctx.lineWidth = 1;
 53→
 54→                        for (let i = 0; i < SPEED_LINE_COUNT; i++) {
 55→                            const angle = (i / SPEED_LINE_COUNT) * TWO_PI;
 56→                            const outerR = 200 + speedRatio * 300 + Math.sin(time * 0.002 + i) * 20;
 57→                            const innerR = 40 + speedRatio * 60;
 58→                            ctx.beginPath();
 59→                            ctx.moveTo(
 60→                                cx + Math.cos(angle) * outerR,
 61→                                cy + Math.sin(angle) * outerR
 62→                            );
 63→                            ctx.lineTo(
 64→                                cx + Math.cos(angle) * innerR,
 65→                                cy + Math.sin(angle) * innerR
 66→                            );
 67→                            ctx.stroke();
 68→                        }
 69→                    }
 70→
 71→                    // ── 2. Stars (painter's algorithm, far first) ────────
 72→                    for (let si = 0; si < sorted.length; si++) {
 73→                        const idx = sorted[si];
 74→                        const star = stars[idx];
 75→                        const projected = project(star, cx, cy);
 76→
 77→                        // Null guard — star is behind camera
 78→                        if (!projected) continue;
 79→
 80→                        const { projX, projY, scale } = projected;
 81→
 82→                        // Viewport cull
 83→                        if (projX < cx - bufferX || projX > cx + bufferX ||
 84→                            projY < cy - bufferY || projY > cy + bufferY) continue;
 85→
 86→                        const baseRadius = star.radius * scale * 0.08;
 87→                        if (baseRadius < 0.3) continue;
 88→
 89→                        const stretchX = 1 + speedRatio * 2.5;
 90→                        const opacity = Math.max(0.1, 1 - speedRatio * 0.6);
 91→                        const drawR = Math.min(baseRadius, 60);
 92→                        const { r, g, b } = star.colorRgb;
 93→
 94→                        ctx.save();
 95→                        ctx.translate(projX, projY);
 96→                        ctx.scale(stretchX, 1);
 97→
 98→                        // Outer glow
 99→                        const glowR = drawR * 2.5;
100→                        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, glowR);
101→                        grad.addColorStop(0, `rgba(${r},${g},${b},${opacity * 0.5})`);
102→                        grad.addColorStop(0.4, `rgba(${r},${g},${b},${opacity * 0.15})`);
103→                        grad.addColorStop(1, 'rgba(0,0,0,0)');
104→                        ctx.beginPath();
105→                        ctx.arc(0, 0, glowR, 0, TWO_PI);
106→                        ctx.fillStyle = grad;
107→                        ctx.fill();
108→
109→                        // Core (white-hot center)
110→                        const coreR = drawR * 0.4;
111→                        ctx.beginPath();
112→                        ctx.arc(0, 0, Math.max(coreR, 0.5), 0, TWO_PI);
113→                        ctx.fillStyle = `rgba(255,255,255,${opacity * 0.9})`;
114→                        ctx.fill();
115→
116→                        ctx.restore();
117→
118→                        // ── Dynamic label (when close) ───────────────────
119→                        const viewZ = star.viewZ;
120→                        if (viewZ > 0 && viewZ < LABEL_Z_MAX) {
121→                            const labelOpacity = (1 - viewZ / LABEL_Z_MAX) * (1 - speedRatio * 0.8);
122→                            if (labelOpacity > 0.05) {
123→                                const rawFontSize = focalLength * star.radius / viewZ * 0.015;
124→                                const fontSize = Math.max(10, Math.min(18, rawFontSize));
125→                                const labelY = projY + drawR * stretchX * 1.8 + fontSize;
126→
127→                                // Title
128→                                ctx.font = `bold ${fontSize}px sans-serif`;
129→                                ctx.fillStyle = `rgba(255,255,255,${labelOpacity * 0.9})`;
130→                                ctx.textAlign = 'center';
131→                                ctx.fillText(star.title, projX, labelY);
132→
133→                                // Author (smaller, blue-tinted)
134→                                const authorSize = Math.max(9, fontSize * 0.75);
135→                                ctx.font = `${authorSize}px sans-serif`;
136→                                ctx.fillStyle = `rgba(140,180,255,${labelOpacity * 0.7})`;
137→                                ctx.fillText(star.authorName, projX, labelY + authorSize + 2);
138→                            }
139→                        }
140→
141→                        // ── 3. Targeting bracket ─────────────────────────
142→                        if (idx === targetIdx) {
143→                            const pulse = 0.6 + 0.4 * Math.sin(time * 0.004);
144→                            const bracketSize = Math.max(drawR * stretchX * 4, 18);
145→                            const half = bracketSize / 2;
146→                            const arm = bracketSize * 0.35;
147→
148→                            ctx.strokeStyle = `rgba(0,255,255,${pulse})`;
149→                            ctx.lineWidth = 1.5;
150→                            ctx.setLineDash([3, 3]);
151→
152→                            // Top-left
153→                            ctx.beginPath();
154→                            ctx.moveTo(projX - half, projY - half + arm);
155→                            ctx.lineTo(projX - half, projY - half);
156→                            ctx.lineTo(projX - half + arm, projY - half);
157→                            ctx.stroke();
158→
159→                            // Top-right
160→                            ctx.beginPath();
161→                            ctx.moveTo(projX + half - arm, projY - half);
162→                            ctx.lineTo(projX + half, projY - half);
163→                            ctx.lineTo(projX + half, projY - half + arm);
164→                            ctx.stroke();
165→
166→                            // Bottom-right
167→                            ctx.beginPath();
168→                            ctx.moveTo(projX + half, projY + half - arm);
169→                            ctx.lineTo(projX + half, projY + half);
170→                            ctx.lineTo(projX + half - arm, projY + half);
171→                            ctx.stroke();
172→
173→                            // Bottom-left
174→                            ctx.beginPath();
175→                            ctx.moveTo(projX - half + arm, projY + half);
176→                            ctx.lineTo(projX - half, projY + half);
177→                            ctx.lineTo(projX - half, projY + half - arm);
178→                            ctx.stroke();
179→
180→                            ctx.setLineDash([]);
181→                        }
182→                    }
183→                }}
184→                perfectDrawEnabled={false}
185→                listening={false}
186→            />
187→        </Layer>
188→    );
189→});
190→
191→RocketLayer.displayName = 'RocketLayer';
192→
193→export default RocketLayer;
