 998→            {universeMode === 'pilot' && (
 999→                <RocketHUD
1000→                    rocketMode={rocketMode}
1001→                    onExit={handleExitRocket}
1002→                    onInteract={handleRocketInteract}
1003→                />
1004→            )}
1005→        </div>
1006→    );
