## 14. Integration into Universe.jsx -- Modified handleRocketInteract

The existing `handleRocketInteract` becomes a dual-path handler:

```js
const selectedGalaxyUserIdRef = useRef(null);

const handleRocketInteract = useCallback(() => {
    const post = rocketMode.getTargetedPost();
    if (!post) return;

    const docking = rocketMode.dockingStateRef?.current;

    // If already docking, ignore
    if (docking === 'approaching' || docking === 'flash' || docking === 'done') return;

    // If star is close enough, ENTER acts as manual dock trigger
    const idx = rocketMode.targetIndexRef.current;
    const star = rocketMode.starsRef.current[idx];

    if (star && star.viewZ < MAGNET_THRESHOLD_Z) {
        // Start docking sequence
        rocketMode.setDockingCallback(() => {
            // Save session
            const snapshot = rocketMode.getSessionSnapshot();
            sessionStorage.setItem('rocketSession', JSON.stringify({
                ...snapshot,
                galaxyUserId: selectedGalaxyUserIdRef.current,
                postId: post.id,
            }));
            navigate(`/home/post/${post.id}`, { state: { fromRocket: true } });
        });
        rocketMode.dockingStateRef.current = 'approaching';
        rocketMode.dockingTargetIdxRef.current = idx;
        rocketMode.dockingStartTimeRef.current = performance.now();
        rocketMode.dockingProgressRef.current = 0;
        rocketMode.dockingStarScaleRef.current = 1;
        rocketMode.inputFrozenRef.current = true;
    } else {
        // Far away -- direct navigate (existing behavior, fallback)
        navigate(`/home/post/${post.id}`);
    }
}, [rocketMode, navigate]);
```

