.rocketWarpIn {
    position: absolute;
    inset: 0;
    z-index: 1030;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        rgba(95, 146, 255, 0.35) 0%,
        rgba(0, 0, 0, 0.9) 70%,
        rgba(0, 0, 0, 1) 100%
    );
    animation: rocketWarpInAnim 1s ease-out forwards;
}

@keyframes rocketWarpInAnim {
    0% {
        opacity: 0;
        transform: scale(1);
    }
    40% {
        opacity: 1;
    }
    100% {
        opacity: 0;
        transform: scale(3);
    }
}

.rocketPitch {
    position: absolute;
    top: 16px;
    right: 16px;
    font-size: 13px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.4);
    pointer-events: none;
}

@keyframes rocketPromptPulse {
    0%, 100% {
        opacity: 0.5;
    }
    50% {
        opacity: 1;
    }
}
